// HTML-Parser für JoyClub Eventseiten
function parseEvents(html, isArchive) {
  const events = [];
  if (!html) return events;

  // Event-Links extrahieren: href="/event/ID.slug.html"
  const linkRe = /href="(\/event\/\d+\.[^"]+\.html)"/g;
  const processed = new Set();
  let m;

  while ((m = linkRe.exec(html)) !== null) {
    const path = m[1];
    if (processed.has(path)) continue;
    processed.add(path);

    const link = 'https://www.joyclub.de' + path;
    const idMatch = path.match(/\/event\/(\d+)\./)
    const id = idMatch ? idMatch[1] : '';

    // Kontext um den Link (2000 Zeichen)
    const idx = m.index;
    const ctx = html.slice(Math.max(0, idx - 500), idx + 1500);

    // Titel: Text im <a>-Tag
    const titleM = ctx.match(/<a[^>]*href="[^"]*\/event\/[^"]+"[^>]*>([\s\S]*?)<\/a>/);
    let name = '';
    if (titleM) {
      name = titleM[1].replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
    }
    if (!name) continue;

    // Datum: z.B. "Samstag, 15.05.2026" oder "15.05.2026"
    let datum = '';
    let isoDatum = '';
    const datumM = ctx.match(/(\d{2}\.\d{2}\.\d{4})/);
    if (datumM) {
      datum = datumM[1];
      const [d, mo, y] = datum.split('.');
      isoDatum = y + '-' + mo + '-' + d;
    }

    // Angemeldete: "X Personen angemeldet"
    let angemeldet = 0;
    const anmM = ctx.match(/(\d+)\s+Person(?:en)?\s+angemeldet/);
    if (anmM) angemeldet = parseInt(anmM[1]);

    // Ort/Location: Text nach dem Event-Block
    let ort = '';
    const ortM = ctx.match(/(?:in|·|@)\s+([A-ZÄÖÜ][a-zA-ZÄÖÜäöüß\s\-]{2,30})(?:<|,|\n)/);
    if (ortM) ort = ortM[1].trim();

    events.push({ id, name, datum, isoDatum, link, angemeldet, ort, archiv: isArchive });
  }

  return events;
}

const upcomingHtml = $('JoyClub: Aktuelle Events').item(0)?.json?.data || '';
const archiveHtml  = $('JoyClub: Archiv Events').item(0)?.json?.data || '';

const upcoming = parseEvents(upcomingHtml, false);
const archive  = parseEvents(archiveHtml, true);

return [{ json: { upcoming, archive, fetchedAt: new Date().toISOString() } }];
